arguments.command:
cd /tmp/sv-c827a85dc6dc41aca6876e2af7e3b609 && \
# Get all relevant symbols with addresses and sizes for offset calculation
readelf -sW libmonosgen-2.0.so.dbg | grep -w FUNC | sort -k2 | awk '
BEGIN { split("0x222098 0x2241ac 0x1abc80 0x1abd14 0x16dfa4 0x16db6c 0x16de04", targets) }
{ addr = strtonum("0x" $2); size = strtonum($3); name = $8 }
{ syms[NR] = name; addrs[NR] = addr; sizes[NR] = size; count = NR }
END {
  for (t in targets) {
    taddr = strtonum(targets[t])
    best = ""; bestaddr = 0
    for (i = 1; i <= count; i++) {
      if (addrs[i] <= taddr && addrs[i] > bestaddr) {
        bestaddr = addrs[i]
        best = syms[i]
        bestsize = sizes[i]
      }
    }
    offset = taddr - bestaddr
    printf "%s -> %s+0x%x (func at 0x%x, size %d)\n", targets[t], best, offset, bestaddr, bestsize
  }
}' 2>&1 | sort

