arguments.command:
cd /tmp/sv-c827a85dc6dc41aca6876e2af7e3b609 && \
# Use nm to get sorted symbols, then find the actual containing function for each PC
nm -n --defined-only libmonosgen-2.0.so.dbg 2>/dev/null | grep -i " [tT] " > /tmp/mono_syms.txt
wc -l /tmp/mono_syms.txt
# For each target address, find the closest preceding symbol
for addr in 0x222098 0x2241ac 0x1abc80 0x1abd14 0x16dfa4 0x16db6c 0x16de04; do
  echo "--- PC $addr ---"
  # Find the last symbol at or before this address
  awk -v target="$addr" '
  BEGIN { tgt = strtonum(target) }
  { a = strtonum("0x" $1) }
  a <= tgt { name = $3; saddr = a }
  a > tgt { printf "  %s+0x%x\n", name, tgt - saddr; exit }
  END { if (name) printf "  %s+0x%x\n", name, tgt - saddr }
  ' /tmp/mono_syms.txt
done

