arguments.command:
cd /tmp/sv-c827a85dc6dc41aca6876e2af7e3b609 && \
# Get all FUNC symbols sorted by address numerically
readelf -sW libmonosgen-2.0.so.dbg | awk '/FUNC/ && $2 != "00000000" { print strtonum("0x"$2), $3, $8 }' | sort -n > /tmp/mono_funcs.txt
# Now find containing function for each PC
for addr in 0x222098 0x2241ac 0x1abc80 0x1abd14 0x16dfa4 0x16db6c 0x16de04; do
  dec=$(printf "%d" "$addr")
  awk -v tgt="$dec" -v hexaddr="$addr" '
  $1 <= tgt { name = $3; saddr = $1; size = $2 }
  $1 > tgt { 
    off = tgt - saddr
    if (off < size) printf "%s -> %s+0x%x (within bounds)\n", hexaddr, name, off
    else printf "%s -> %s+0x%x (past end, size=0x%x - likely inlined/static)\n", hexaddr, name, off, size
    exit
  }
  END { 
    if (name) {
      off = tgt - saddr
      if (off < size) printf "%s -> %s+0x%x (within bounds)\n", hexaddr, name, off
      else printf "%s -> %s+0x%x (past end, size=0x%x)\n", hexaddr, name, off, size
    }
  }
  ' /tmp/mono_funcs.txt
done

